const { PrismaClient } = require('@prisma/client')
const bcrypt = require('bcryptjs')

const prisma = new PrismaClient()

 
async function rebuildQuestionBankStats() {
  const grouped = await prisma.questionBank.groupBy({
    by: ['domain', 'category', 'phase', 'level'],
    where: { isActive: true },
    _count: { _all: true },
  })

  await prisma.questionBankStats.deleteMany({})
  for (const g of grouped) {
    const { domain, category, phase, level } = g
    if (!domain || !category || !level) continue
    await prisma.questionBankStats.create({
      data: { domain, category, phase, level, count: g._count._all },
    })
  }
  console.log(`✅ Rebuilt QuestionBankStats (${grouped.length} buckets)`)
}

